def list_instances() -> List[str]:
    """Return all available instance names."""
    return sorted(INSTANCES.keys())

def get_instance(name: str) -> Dict[str, Any]:
    """Return a deep-copied instance dict so you can modify it safely."""
    if name not in INSTANCES:
        raise KeyError(f"Unknown instance: {name}. Available: {', '.join(list_instances())}")
    return deepcopy(INSTANCES[name])

def write_customer_data_py(name: str, out_file: str) -> None:
    """
    Export one instance into a standalone customer_data.py-style module.
    This is handy if your current code expects `import customer_data`.
    """
    inst = get_instance(name)
    num_customers = inst["num_customers"]
    locations = inst["locations"]
    demand = inst["demand"]
    depot = inst["depot"]
    vehicle_capacity = inst["vehicle_capacity"]
    battery_capacity = inst["battery_capacity"]
    num_vehicles = inst["num_vehicles"]

    with open(out_file, "w", encoding="utf-8") as f:
        f.write("# Auto-generated from Mavrovouniotis et al. (2020) E-CVRP benchmarks\n")
        f.write(f"# Instance: {name}\n\n")
        f.write(f"num_customers = {num_customers}\n")
        f.write(f"locations = {locations!r}\n")
        f.write(f"demand = {demand!r}\n")
        f.write(f"depot = {depot}\n")
        f.write(f"vehicle_capacity = {vehicle_capacity}\n")
        f.write(f"battery_capacity = {battery_capacity}\n")
        f.write(f"num_vehicles = {num_vehicles}\n")
